using System.Globalization;using BgCommon.Localization;namespace BgCommon.UI.Designer.Localization{    /// <summary>    /// 本地化服务    /// </summary>    public class LocalizationService    {        private readonly LocalizationProvider _localizationProvider;                /// <summary>        /// 本地化提供程序        /// </summary>        public LocalizationProvider LocalizationProvider => _localizationProvider;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="localizationSets">本地化资源集合</param>        public LocalizationService(IEnumerable<LocalizationSet> localizationSets)        {            // 默认使用系统语言            var defaultCulture = CultureInfo.CurrentUICulture;            _localizationProvider = new LocalizationProvider(defaultCulture, localizationSets);        }                /// <summary>        /// 获取本地化字符串        /// </summary>        /// <param name="key">资源键名</param>        /// <param name="assemblyName">程序集名称</param>        /// <returns>本地化字符串</returns>        public string GetString(string key, string assemblyName = null)        {            return _localizationProvider.GetString(key, assemblyName);        }                /// <summary>        /// 获取指定语言的本地化字符串        /// </summary>        /// <param name="key">资源键名</param>        /// <param name="culture">语言区域</param>        /// <param name="assemblyName">程序集名称</param>        /// <returns>本地化字符串</returns>        public string GetString(string key, CultureInfo culture, string assemblyName = null)        {            return _localizationProvider.GetString(key, culture, assemblyName);        }                /// <summary>        /// 设置当前语言        /// </summary>        /// <param name="culture">语言区域</param>        public void SetCulture(CultureInfo culture)        {            _localizationProvider.SetCulture(culture);        }                /// <summary>        /// 获取当前语言        /// </summary>        /// <returns>当前语言区域</returns>        public CultureInfo GetCurrentCulture()        {            return _localizationProvider.GetCulture();        }                /// <summary>        /// 当语言发生变化时触发的事件        /// </summary>        public event EventHandler<CultureInfo> CultureChanged        {            add { _localizationProvider.CultureChanged += value; }            remove { _localizationProvider.CultureChanged -= value; }        }    }}